// PHASE 4 ORCHESTRATOR — pure planning step.
// Reads alerts + playbooks + recent actions + paused breakers + recent
// health rows, decides which actions to execute or propose, returns a
// flat list of action records. The next nodes apply each record.
const allOf = function (name) { try { const items = $(name).all().map(function (i) { return i.json; }); if (items.length === 1 && Array.isArray(items[0])) return items[0]; return items; } catch (e) { return []; } };
const alerts    = allOf('Fetch Open Alerts');
const playbooks = allOf('Fetch Playbooks');
const actions   = allOf('Fetch Recent Actions');
const paused    = allOf('Fetch Paused Breakers');
const health    = allOf('Fetch Recent Health');

const SEV_RANK = { warning: 1, critical: 2, emergency: 3 };
const sevOK = function (sev, min) { return (SEV_RANK[sev] || 0) >= (SEV_RANK[min] || 1); };

function lastActionFor(playbookName, target) {
  // Recent action of the same playbook + same target — used for cooldown.
  let latest = null;
  actions.forEach(function (a) {
    const data = a.action_data || {};
    if (data.playbook_name !== playbookName) return;
    if (target && a.target_resource !== target) return;
    if (!latest || a.created_at > latest.created_at) latest = a;
  });
  return latest;
}

function inCooldown(playbook, target) {
  const last = lastActionFor(playbook.playbook_name, target);
  if (!last) return false;
  const ageMin = (Date.now() - new Date(last.created_at).getTime()) / 60000;
  return ageMin < (playbook.cooldown_minutes || 60);
}

const planned = [];

// === Alert-driven playbooks ===
playbooks.forEach(function (pb) {
  const matching = alerts.filter(function (a) {
    if (a.module_name !== pb.trigger_module) return false;
    if (pb.trigger_alert_type && a.alert_type !== pb.trigger_alert_type) return false;
    if (!sevOK(a.severity, pb.trigger_severity_min)) return false;
    return true;
  });
  matching.forEach(function (alert) {
    // Determine target_resource per action_type.
    let target = null;
    const det = alert.details || {};
    if (pb.action_type === 'pause_workflow' || pb.action_type === 'resume_workflow') {
      target = det.workflow_id || det.workflow_name || null;
    } else if (pb.action_type === 'block_ip') {
      target = det.source_ip || (det.group_by === 'source_ip' ? det.group_value : null);
    } else if (pb.action_type === 'propose_account_lockout') {
      target = det.user_email || (det.group_by === 'user_email' ? det.group_value : null);
      // Additional gate: only fire if min_alerts_in_24h same-email brute_force alerts.
      const minAlerts = (pb.action_config && pb.action_config.min_alerts_in_24h) || 3;
      const sameEmailAlerts = alerts.filter(function (a) {
        return a.alert_type === 'security_brute_force' && (a.details || {}).group_value === target;
      });
      if (sameEmailAlerts.length < minAlerts) return;
    } else if (pb.action_type === 'propose_credential_revocation') {
      target = det.credential_name || null;
      const minDays = (pb.action_config && pb.action_config.min_overdue_days) || 30;
      if ((det.days_to_due || 0) > -minDays) return;
    }
    if (!target) return;
    if (inCooldown(pb, target)) return;
    planned.push({
      playbook_name: pb.playbook_name,
      module_name: pb.trigger_module,
      action_type: pb.action_type,
      target_resource: target,
      requires_approval: !!pb.requires_approval,
      alert_id: alert.id,
      action_config: pb.action_config || {},
      reason: ((pb.action_config && pb.action_config.reason_prefix) || ('Playbook ' + pb.playbook_name)) + ' — ' + (alert.title || ''),
      source_alert: { id: alert.id, title: alert.title, severity: alert.severity, alert_type: alert.alert_type, details: alert.details }
    });
  });
});

// === Time-driven playbook: auto_resume_when_healthy ===
const resumePb = playbooks.find(function (p) { return p.playbook_name === 'auto_resume_when_healthy' && p.active; });
if (resumePb) {
  paused.forEach(function (br) {
    if (br.is_essential) return;  // never touch essential (defense in depth)
    if (inCooldown(resumePb, br.workflow_id)) return;
    // Filter recent health for this workflow, latest first.
    const recent = health.filter(function (h) { return h.workflow_id === br.workflow_id; }).slice(0, 3);
    const minWindows = (resumePb.action_config && resumePb.action_config.min_consecutive_healthy_windows) || 3;
    if (recent.length < minWindows) return;
    if (!recent.every(function (h) { return h.status === 'healthy'; })) return;
    planned.push({
      playbook_name: resumePb.playbook_name,
      module_name: resumePb.trigger_module,
      action_type: 'resume_workflow',
      target_resource: br.workflow_id,
      requires_approval: false,
      alert_id: null,
      action_config: resumePb.action_config || {},
      reason: 'Sentinel: ' + minWindows + ' consecutive healthy windows after pause',
      source_alert: null
    });
  });
}

return planned.map(function (p) { return { json: p }; });

// EXECUTOR — for auto actions only. Builds the SQL payload pieces.
// We have one Code node per branch because the side effects differ:
//   - pause_workflow:    PATCH sentinel_workflow_breakers + INSERT action
//   - resume_workflow:   PATCH sentinel_workflow_breakers + INSERT action
//   - block_ip:          INSERT sentinel_ip_blocklist + INSERT action
//   - notify_only:       INSERT action only
// For simplicity we route each action_type into the same downstream
// HTTP-PATCH/INSERT nodes using a small router. This Code node
// emits an array of side-effect descriptors that the next nodes apply.
const p = $input.item.json;
const now = new Date().toISOString();
let plus = null;
if (p.action_type === 'block_ip') {
  const dur = (p.action_config && p.action_config.block_duration_minutes) || 60;
  const exp = new Date(Date.now() + dur * 60 * 1000).toISOString();
  plus = { kind: 'block_ip_insert', body: { ip_address: p.target_resource, expires_at: exp, reason: p.reason, blocked_by: 'auto:' + p.playbook_name, alert_id: p.alert_id, active: true } };
} else if (p.action_type === 'pause_workflow') {
  plus = { kind: 'breaker_patch', filter: 'workflow_id=eq.' + encodeURIComponent(p.target_resource), body: { current_status: 'paused', paused_at: now, paused_reason: p.reason, updated_at: now } };
} else if (p.action_type === 'resume_workflow') {
  plus = { kind: 'breaker_patch', filter: 'workflow_id=eq.' + encodeURIComponent(p.target_resource), body: { current_status: 'active', paused_at: null, paused_reason: null, updated_at: now } };
} else {
  plus = { kind: 'noop' };
}
const actionRow = {
  module_name: p.module_name,
  action_type: p.action_type,
  target_resource: p.target_resource,
  action_data: { playbook_name: p.playbook_name, reason: p.reason, action_config: p.action_config, source_alert: p.source_alert },
  triggered_by: 'auto:' + p.playbook_name,
  status: 'succeeded',
  executed_at: now,
  human_approved: false
};
return { json: { plus: plus, action_row: actionRow } };

// PENDING approval — write sentinel_actions with status='pending'.
const p = $input.item.json;
const row = {
  module_name: p.module_name,
  action_type: p.action_type,
  target_resource: p.target_resource,
  action_data: { playbook_name: p.playbook_name, reason: p.reason, action_config: p.action_config, source_alert: p.source_alert },
  triggered_by: 'auto:' + p.playbook_name,
  status: 'pending',
  human_approved: false
};
return { json: row };

const planned = $('Plan Actions').all().map(function (i) { return i.json; });
const auto = planned.filter(function (p) { return !p.requires_approval; });
const pending = planned.filter(function (p) { return p.requires_approval; });
return { json: { ok: true, planned_total: planned.length, auto_executed: auto.length, pending_approval: pending.length, sample_targets: planned.slice(0, 10).map(function (p) { return p.playbook_name + ' → ' + p.target_resource; }) } };
